  out->blit_plan_safe = 1;
  out->route_selected = 1;
  out->route_blocked = 0;
  out->action_allowed = output_plan->action_allowed ? 1 : 0;
  out->action_blocked = output_plan->action_blocked ? 1 : 0;
  out->input_focus_allowed = output_plan->input_focus_allowed ? 1 : 0;
