int login_window_credential_screen_window_surface_plan_build(
    const struct login_window_credential_screen_window_plan *window_plan,
    struct login_window_credential_screen_window_surface_plan *out) {
  if (!out) return -1;
  login_window_credential_screen_window_surface_plan_reset(
      out, window_plan ? 1 : 0);
  if (!window_plan) return 0;
  out->requested_action = window_plan->requested_action;
  out->window_plan_safe = window_plan->window_plan_safe ? 1 : 0;
  if (!login_window_credential_screen_window_surface_plan_window_is_safe(
          window_plan)) {
    out->event_type = "credential-screen-window-surface-plan-unsafe";
    out->blocked_reason = "credential-window-surface-plan-unsafe";
    out->message = "Credential screen window surface plan unsafe; use text login.";
    return 0;
  }
  out->window_surface_plan_safe = 1;
  out->route_selected = 1;
  out->route_blocked = 0;
  out->action_allowed = window_plan->action_allowed ? 1 : 0;
  out->action_blocked = window_plan->action_blocked ? 1 : 0;
  out->input_focus_allowed = window_plan->input_focus_allowed ? 1 : 0;
  login_window_credential_screen_window_surface_plan_copy_safe_fields(
      window_plan, out);
  out->surface_allowed = 1;
  out->surface_ticket_selected = 1;
  out->surface_target_selected = 1;
  out->surface_error = 0;
  out->surface_policy = "declarative-surface-no-bind";
  out->event_type = "credential-screen-window-surface-plan-ready";
  out->state = "window-surface-ready";
  out->message = "Credential screen window surface ticket ready; no surface bound.";
  out->blocked_reason = window_plan->blocked_reason;
  if (window_plan->submit_requested) {
    out->surface_ticket = "text-login-fallback-window-surface-ticket";
    out->compositor_target = "text-login-fallback-window-surface";
    out->surface_policy = "fallback-window-surface-declarative";
    out->surface_text_login = 1;
    out->surface_text_login_fallback = 1;
    out->action_allowed = 0;
    out->action_blocked = 1;
    out->input_focus_allowed = 0;
    out->state = "window-surface-text-login-ready";
    out->message = "Graphical submit is disabled; use text login.";
    out->blocked_reason = "gui-submit-disabled";
    return 0;
  }
  if (window_plan->window_credential_panel &&
      window_plan->window_credential_input &&
      window_plan->window_credential_focus && out->action_allowed &&
      !out->action_blocked && out->input_focus_allowed) {
    out->surface_ticket = "credential-screen-window-surface-ticket";
    out->compositor_target = "credential-screen-window-surface";
    out->surface_credential_panel = 1;
    out->surface_credential_input = 1;
    out->surface_credential_focus = 1;
    out->surface_text_login = 0;
    out->surface_text_login_fallback = 0;
    out->state = "window-surface-credential-ready";
    out->message = "Credential window surface ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  if (window_plan->window_text_recovery &&
      out->recovery_text_session_required) {
    out->surface_ticket = "text-recovery-window-surface-ticket";
    out->compositor_target = "text-recovery-window-surface";
    out->surface_text_recovery = 1;
    out->surface_text_login = 1;
    out->surface_text_login_fallback = 0;
    out->input_focus_allowed = 0;
    out->state = "window-surface-text-recovery-ready";
    out->message = "Text recovery window surface ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "text-recovery-only";
    return 0;
  }
  if (window_plan->window_text_login_resume &&
      out->session_reset_required && out->login_screen_rerender_required) {
    out->surface_ticket = "text-login-resume-window-surface-ticket";
    out->compositor_target = "text-login-resume-window-surface";
    out->surface_policy = "full-window-surface-declarative";
    out->surface_text_login = 1;
    out->surface_text_login_resume = 1;
    out->surface_text_login_fallback = 0;
    out->input_focus_allowed = 0;
    out->state = "window-surface-resume-ready";
    out->message = "Text login resume window surface ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  out->surface_ticket = "text-login-fallback-window-surface-ticket";
  out->compositor_target = "text-login-fallback-window-surface";
  out->surface_policy = "fallback-window-surface-declarative";
  out->surface_text_login = 1;
  out->surface_text_login_fallback = 1;
  out->action_allowed = 0;
  out->action_blocked = 1;
  out->input_focus_allowed = 0;
  out->state = "window-surface-text-login-ready";
  out->message = "Use authoritative text login.";
  return 0;
}

