int login_window_credential_screen_window_present_plan_build(
    const struct login_window_credential_screen_window_damage_plan *damage_plan,
    struct login_window_credential_screen_window_present_plan *out) {
  if (!out) return -1;
  login_window_credential_screen_window_present_plan_reset(
      out, damage_plan ? 1 : 0);
  if (!damage_plan) return 0;
  out->requested_action = damage_plan->requested_action;
  out->window_compositor_plan_available =
      damage_plan->window_compositor_plan_available ? 1 : 0;
  out->window_surface_plan_available =
      damage_plan->window_surface_plan_available ? 1 : 0;
  out->window_surface_plan_safe = damage_plan->window_surface_plan_safe ? 1 : 0;
  out->window_compositor_plan_safe =
      damage_plan->window_compositor_plan_safe ? 1 : 0;
  out->window_damage_plan_safe = damage_plan->window_damage_plan_safe ? 1 : 0;
  if (!login_window_credential_screen_window_present_plan_damage_is_safe(
          damage_plan)) {
    out->event_type = "credential-screen-window-present-plan-unsafe";
    out->blocked_reason = "credential-window-present-plan-unsafe";
    out->message =
        "Credential screen window present plan unsafe; use text login.";
    return 0;
  }
  out->window_present_plan_safe = 1;
  out->route_selected = 1;
  out->route_blocked = 0;
  out->action_allowed = damage_plan->action_allowed ? 1 : 0;
  out->action_blocked = damage_plan->action_blocked ? 1 : 0;
  out->input_focus_allowed = damage_plan->input_focus_allowed ? 1 : 0;
  login_window_credential_screen_window_present_plan_copy_safe_fields(
      damage_plan, out);
  out->damage_error = 0;
  out->present_allowed = 1;
  out->present_ticket_selected = 1;
  out->present_target_selected = 1;
  out->present_error = 0;
  out->present_policy = "full-window-present-declarative";
  out->cache_policy = "window-present-cache-disabled";
  out->event_type = "credential-screen-window-present-plan-ready";
  out->state = "window-present-ready";
  out->message =
      "Credential screen window present ticket ready; no present submitted.";
  out->blocked_reason = damage_plan->blocked_reason;
  if (damage_plan->submit_requested) {
    out->present_ticket = "text-login-fallback-window-present-ticket";
    out->compositor_target = "text-login-fallback-window-present";
    out->present_policy = "fallback-window-present-declarative";
    out->present_text_login = 1;
    out->present_text_login_fallback = 1;
    out->full_present_required = 1;
    out->present_incremental_allowed = 0;
    out->present_cache_allowed = 0;
    out->present_reuse_allowed = 0;
    out->action_allowed = 0;
    out->action_blocked = 1;
    out->input_focus_allowed = 0;
    out->state = "window-present-text-login-ready";
    out->message = "Graphical submit is disabled; use text login.";
    out->blocked_reason = "gui-submit-disabled";
    return 0;
  }
  if (damage_plan->damage_credential_panel &&
      damage_plan->damage_credential_input &&
      damage_plan->damage_credential_focus && out->action_allowed &&
      !out->action_blocked && out->input_focus_allowed) {
    out->present_ticket = "credential-screen-window-present-ticket";
    out->compositor_target = "credential-screen-window-present";
    out->present_policy = "incremental-window-present-declarative";
    out->cache_policy = "window-present-cache-eligible";
    out->present_incremental_allowed = 1;
    out->full_present_required = 0;
    out->present_cache_allowed = 1;
    out->present_reuse_allowed = 1;
    out->present_credential_panel = 1;
    out->present_credential_input = 1;
    out->present_credential_focus = 1;
    out->present_text_login = 0;
    out->present_text_login_fallback = 0;
    out->state = "window-present-credential-ready";
    out->message = "Credential window present ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  if (damage_plan->damage_text_recovery &&
      out->recovery_text_session_required) {
    out->present_ticket = "text-recovery-window-present-ticket";
    out->compositor_target = "text-recovery-window-present";
    out->present_text_recovery = 1;
    out->present_text_login = 1;
    out->present_text_login_fallback = 0;
    out->full_present_required = 1;
    out->present_incremental_allowed = 0;
    out->present_cache_allowed = 0;
    out->present_reuse_allowed = 0;
    out->input_focus_allowed = 0;
    out->state = "window-present-text-recovery-ready";
    out->message = "Text recovery window present ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "text-recovery-only";
    return 0;
  }
  if (damage_plan->damage_text_login_resume &&
      out->session_reset_required && out->login_screen_rerender_required) {
    out->present_ticket = "text-login-resume-window-present-ticket";
    out->compositor_target = "text-login-resume-window-present";
    out->present_policy = "full-window-present-declarative";
    out->cache_policy = "window-present-cache-bypassed-for-rerender";
    out->present_text_login = 1;
    out->present_text_login_resume = 1;
    out->present_text_login_fallback = 0;
    out->full_present_required = 1;
    out->present_incremental_allowed = 0;
    out->present_cache_allowed = 0;
    out->present_reuse_allowed = 0;
    out->input_focus_allowed = 0;
    out->state = "window-present-resume-ready";
    out->message = "Text login resume window present ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  out->present_ticket = "text-login-fallback-window-present-ticket";
  out->compositor_target = "text-login-fallback-window-present";
  out->present_policy = "fallback-window-present-declarative";
  out->present_text_login = 1;
  out->present_text_login_fallback = 1;
  out->full_present_required = 1;
  out->present_incremental_allowed = 0;
  out->present_cache_allowed = 0;
  out->present_reuse_allowed = 0;
  out->action_allowed = 0;
  out->action_blocked = 1;
  out->input_focus_allowed = 0;
  out->state = "window-present-text-login-ready";
  out->message = "Use authoritative text login.";
  return 0;
}

