int login_window_credential_screen_window_schedule_plan_build(
    const struct login_window_credential_screen_window_present_plan *present_plan,
    struct login_window_credential_screen_window_schedule_plan *out) {
  if (!out) return -1;
  login_window_credential_screen_window_schedule_plan_reset(
      out, present_plan ? 1 : 0);
  if (!present_plan) return 0;
  out->requested_action = present_plan->requested_action;
  out->window_damage_plan_available =
      present_plan->window_damage_plan_available ? 1 : 0;
  out->window_compositor_plan_available =
      present_plan->window_compositor_plan_available ? 1 : 0;
  out->window_surface_plan_available =
      present_plan->window_surface_plan_available ? 1 : 0;
  out->window_surface_plan_safe =
      present_plan->window_surface_plan_safe ? 1 : 0;
  out->window_compositor_plan_safe =
      present_plan->window_compositor_plan_safe ? 1 : 0;
  out->window_damage_plan_safe =
      present_plan->window_damage_plan_safe ? 1 : 0;
  out->window_present_plan_safe =
      present_plan->window_present_plan_safe ? 1 : 0;
  if (!login_window_credential_screen_window_schedule_plan_present_is_safe(
          present_plan)) {
    out->event_type = "credential-screen-window-schedule-plan-unsafe";
    out->blocked_reason = "credential-window-schedule-plan-unsafe";
    out->message =
        "Credential screen window schedule plan unsafe; use text login.";
    return 0;
  }
  out->window_schedule_plan_safe = 1;
  out->route_selected = 1;
  out->route_blocked = 0;
  out->action_allowed = present_plan->action_allowed ? 1 : 0;
  out->action_blocked = present_plan->action_blocked ? 1 : 0;
  out->input_focus_allowed = present_plan->input_focus_allowed ? 1 : 0;
  login_window_credential_screen_window_schedule_plan_copy_safe_fields(
      present_plan, out);
  out->damage_error = 0;
  out->present_error = 0;
  out->schedule_allowed = 1;
  out->schedule_ticket_selected = 1;
  out->schedule_target_selected = 1;
  out->schedule_error = 0;
  out->frame_pacing_allowed = 1;
  out->schedule_policy = out->present_incremental_allowed
                             ? "incremental-window-schedule-declarative"
                             : "full-window-schedule-declarative";
  out->event_type = "credential-screen-window-schedule-plan-ready";
  out->state = "window-schedule-ready";
  out->message =
      "Credential screen window schedule ticket ready; no frame scheduled.";
  out->blocked_reason = present_plan->blocked_reason;
  if (present_plan->submit_requested) {
    out->schedule_ticket = "text-login-fallback-window-schedule-ticket";
    out->compositor_target = "text-login-fallback-window-schedule";
    out->schedule_policy = "fallback-window-schedule-declarative";
    out->schedule_text_login = 1;
    out->schedule_text_login_fallback = 1;
    out->full_schedule_required = 1;
    out->schedule_incremental_allowed = 0;
    out->schedule_cache_allowed = 0;
    out->schedule_reuse_allowed = 0;
    out->action_allowed = 0;
    out->action_blocked = 1;
    out->input_focus_allowed = 0;
    out->state = "window-schedule-text-login-ready";
    out->message = "Graphical submit is disabled; use text login.";
    out->blocked_reason = "gui-submit-disabled";
    return 0;
  }
  if (present_plan->present_credential_panel &&
      present_plan->present_credential_input &&
      present_plan->present_credential_focus && out->action_allowed &&
      !out->action_blocked && out->input_focus_allowed) {
    out->schedule_ticket = "credential-screen-window-schedule-ticket";
    out->compositor_target = "credential-screen-window-schedule";
    out->schedule_incremental_allowed = 1;
    out->full_schedule_required = 0;
    out->schedule_cache_allowed = 1;
    out->schedule_reuse_allowed = 1;
    out->schedule_credential_panel = 1;
    out->schedule_credential_input = 1;
    out->schedule_credential_focus = 1;
    out->schedule_text_login = 0;
    out->schedule_text_login_fallback = 0;
    out->state = "window-schedule-credential-ready";
    out->message =
        "Credential window schedule ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  if (present_plan->present_text_recovery &&
      out->recovery_text_session_required) {
    out->schedule_ticket = "text-recovery-window-schedule-ticket";
    out->compositor_target = "text-recovery-window-schedule";
    out->schedule_text_recovery = 1;
    out->schedule_text_login = 1;
    out->schedule_text_login_fallback = 0;
    out->full_schedule_required = 1;
    out->schedule_incremental_allowed = 0;
    out->schedule_cache_allowed = 0;
    out->schedule_reuse_allowed = 0;
    out->input_focus_allowed = 0;
    out->state = "window-schedule-text-recovery-ready";
    out->message =
        "Text recovery window schedule ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "text-recovery-only";
    return 0;
  }
  if (present_plan->present_text_login_resume &&
      out->session_reset_required && out->login_screen_rerender_required) {
    out->schedule_ticket = "text-login-resume-window-schedule-ticket";
    out->compositor_target = "text-login-resume-window-schedule";
    out->schedule_policy = "full-window-schedule-declarative";
    out->cache_policy = "window-schedule-cache-bypassed-for-rerender";
    out->schedule_text_login = 1;
    out->schedule_text_login_resume = 1;
    out->schedule_text_login_fallback = 0;
    out->full_schedule_required = 1;
    out->schedule_incremental_allowed = 0;
    out->schedule_cache_allowed = 0;
    out->schedule_reuse_allowed = 0;
    out->input_focus_allowed = 0;
    out->state = "window-schedule-resume-ready";
    out->message =
        "Text login resume window schedule ticket ready; graphical authentication remains disabled.";
    out->blocked_reason = "ready";
    return 0;
  }
  out->schedule_ticket = "text-login-fallback-window-schedule-ticket";
  out->compositor_target = "text-login-fallback-window-schedule";
  out->schedule_policy = "fallback-window-schedule-declarative";
  out->schedule_text_login = 1;
  out->schedule_text_login_fallback = 1;
  out->full_schedule_required = 1;
  out->schedule_incremental_allowed = 0;
  out->schedule_cache_allowed = 0;
  out->schedule_reuse_allowed = 0;
  out->action_allowed = 0;
  out->action_blocked = 1;
  out->input_focus_allowed = 0;
  out->state = "window-schedule-text-login-ready";
  out->message = "Use authoritative text login.";
  out->blocked_reason = "ready";
  return 0;
}

