static void login_window_credential_screen_pipeline_safety_report_reset(
    struct login_window_credential_screen_pipeline_safety_report *out,
    int window_input_plan_available) {
  *out = (struct login_window_credential_screen_pipeline_safety_report){0};
  out->version = LOGIN_WINDOW_CREDENTIAL_SCREEN_PIPELINE_SAFETY_REPORT_VERSION;
  out->window_input_plan_available = window_input_plan_available ? 1 : 0;
  out->total_layers = 15;
  out->layers_safe = 0;
  out->layers_unsafe = 15;
  out->no_real_event_dispatched = 1;
  out->no_real_input_dispatched = 1;
  out->deepest_safe_layer = "none";
  out->first_unsafe_layer = "window_surface_plan";
  out->event_type =
      "credential-screen-pipeline-safety-report-unavailable";
  out->state = "blocked";
  out->blocked_reason = "window-input-plan-unavailable";
  out->message =
      "Pipeline safety report unavailable; text login remains authoritative.";
}

int login_window_credential_screen_pipeline_safety_report_build(
    const struct login_window_credential_screen_window_input_plan *input_plan,
    struct login_window_credential_screen_pipeline_safety_report *out) {
  int safe;
  if (!out) return -1;
  login_window_credential_screen_pipeline_safety_report_reset(
      out, input_plan ? 1 : 0);
  if (!input_plan) return 0;

  out->window_surface_plan_safe =
      input_plan->window_surface_plan_safe ? 1 : 0;
  out->window_compositor_plan_safe =
      input_plan->window_compositor_plan_safe ? 1 : 0;
  out->window_damage_plan_safe =
      input_plan->window_damage_plan_safe ? 1 : 0;
  out->window_present_plan_safe =
      input_plan->window_present_plan_safe ? 1 : 0;
  out->window_schedule_plan_safe =
      input_plan->window_schedule_plan_safe ? 1 : 0;
  out->window_vsync_plan_safe =
      input_plan->window_vsync_plan_safe ? 1 : 0;
  out->window_scanout_plan_safe =
      input_plan->window_scanout_plan_safe ? 1 : 0;
  out->window_display_plan_safe =
      input_plan->window_display_plan_safe ? 1 : 0;
  out->window_output_plan_safe =
      input_plan->window_output_plan_safe ? 1 : 0;
  out->window_blit_plan_safe = input_plan->window_blit_plan_safe ? 1 : 0;
  out->window_commit_plan_safe =
      input_plan->window_commit_plan_safe ? 1 : 0;
  out->window_flip_plan_safe = input_plan->window_flip_plan_safe ? 1 : 0;
  out->window_vblank_plan_safe =
      input_plan->window_vblank_plan_safe ? 1 : 0;
  out->window_event_plan_safe =
      input_plan->window_event_plan_safe ? 1 : 0;
  out->window_input_plan_safe =
      input_plan->window_input_plan_safe ? 1 : 0;

  out->layers_safe = out->window_surface_plan_safe +
                     out->window_compositor_plan_safe +
                     out->window_damage_plan_safe +
                     out->window_present_plan_safe +
                     out->window_schedule_plan_safe +
                     out->window_vsync_plan_safe +
                     out->window_scanout_plan_safe +
                     out->window_display_plan_safe +
                     out->window_output_plan_safe +
                     out->window_blit_plan_safe +
                     out->window_commit_plan_safe +
                     out->window_flip_plan_safe +
                     out->window_vblank_plan_safe +
                     out->window_event_plan_safe +
                     out->window_input_plan_safe;
  out->layers_unsafe = out->total_layers - out->layers_safe;

  out->gui_submit_blocked =
      (input_plan->submit_blocked && !input_plan->submit_enabled &&
       !input_plan->submit_callback_bound)
          ? 1
          : 0;
  out->auth_attempt_blocked =
      (!input_plan->auth_attempt_allowed &&
       !input_plan->auth_callback_bound)
          ? 1
          : 0;
  out->credentials_redacted =
      (input_plan->credential_redacted && input_plan->length_redacted &&
       !input_plan->raw_secret_exposed && !input_plan->masked_text_exposed)
          ? 1
          : 0;
  out->credentials_storage_wiped =
      input_plan->credential_storage_wiped ? 1 : 0;
  out->text_login_authoritative =
      input_plan->text_login_authoritative ? 1 : 0;
  out->route_consistent =
      (((input_plan->route_selected ? 1 : 0) ^
        (input_plan->route_blocked ? 1 : 0)) != 0)
          ? 1
          : 0;

  out->no_real_event_dispatched =
      (!input_plan->event_submitted && !input_plan->event_handler_armed &&
       !input_plan->event_handler_submitted &&
       !input_plan->event_queue_armed &&
       !input_plan->event_queue_submitted &&
       !input_plan->event_dispatch_submitted &&
       !input_plan->event_callback_armed &&
       !input_plan->event_callback_submitted &&
       !input_plan->event_timestamp_captured &&
       !input_plan->event_timestamp_submitted &&
       !input_plan->event_frame_completed &&
       !input_plan->event_frame_submitted && !input_plan->event_error)
          ? 1
          : 0;
  out->no_real_input_dispatched =
      (!input_plan->input_submitted && !input_plan->input_keyboard_armed &&
       !input_plan->input_keyboard_submitted &&
       !input_plan->input_pointer_armed &&
       !input_plan->input_pointer_submitted &&
       !input_plan->input_focus_armed &&
       !input_plan->input_focus_submitted &&
       !input_plan->input_keymap_loaded &&
       !input_plan->input_keymap_submitted &&
       !input_plan->input_decode_submitted &&
       !input_plan->input_route_submitted &&
       !input_plan->input_callback_armed &&
       !input_plan->input_callback_submitted &&
       !input_plan->input_grab_allowed &&
       !input_plan->input_grab_submitted && !input_plan->input_error)
          ? 1
          : 0;

  if (!out->window_surface_plan_safe) {
    out->deepest_safe_layer = "none";
    out->first_unsafe_layer = "window_surface_plan";
  } else if (!out->window_compositor_plan_safe) {
    out->deepest_safe_layer = "window_surface_plan";
    out->first_unsafe_layer = "window_compositor_plan";
  } else if (!out->window_damage_plan_safe) {
    out->deepest_safe_layer = "window_compositor_plan";
    out->first_unsafe_layer = "window_damage_plan";
  } else if (!out->window_present_plan_safe) {
    out->deepest_safe_layer = "window_damage_plan";
    out->first_unsafe_layer = "window_present_plan";
  } else if (!out->window_schedule_plan_safe) {
    out->deepest_safe_layer = "window_present_plan";
    out->first_unsafe_layer = "window_schedule_plan";
  } else if (!out->window_vsync_plan_safe) {
    out->deepest_safe_layer = "window_schedule_plan";
    out->first_unsafe_layer = "window_vsync_plan";
  } else if (!out->window_scanout_plan_safe) {
    out->deepest_safe_layer = "window_vsync_plan";
    out->first_unsafe_layer = "window_scanout_plan";
  } else if (!out->window_display_plan_safe) {
    out->deepest_safe_layer = "window_scanout_plan";
    out->first_unsafe_layer = "window_display_plan";
  } else if (!out->window_output_plan_safe) {
    out->deepest_safe_layer = "window_display_plan";
    out->first_unsafe_layer = "window_output_plan";
  } else if (!out->window_blit_plan_safe) {
    out->deepest_safe_layer = "window_output_plan";
    out->first_unsafe_layer = "window_blit_plan";
  } else if (!out->window_commit_plan_safe) {
    out->deepest_safe_layer = "window_blit_plan";
    out->first_unsafe_layer = "window_commit_plan";
  } else if (!out->window_flip_plan_safe) {
    out->deepest_safe_layer = "window_commit_plan";
    out->first_unsafe_layer = "window_flip_plan";
  } else if (!out->window_vblank_plan_safe) {
    out->deepest_safe_layer = "window_flip_plan";
    out->first_unsafe_layer = "window_vblank_plan";
  } else if (!out->window_event_plan_safe) {
    out->deepest_safe_layer = "window_vblank_plan";
    out->first_unsafe_layer = "window_event_plan";
  } else if (!out->window_input_plan_safe) {
    out->deepest_safe_layer = "window_event_plan";
    out->first_unsafe_layer = "window_input_plan";
  } else {
    out->deepest_safe_layer = "window_input_plan";
    out->first_unsafe_layer = "none";
  }

  safe = (out->layers_safe == out->total_layers) &&
         out->gui_submit_blocked && out->auth_attempt_blocked &&
         out->credentials_redacted && out->credentials_storage_wiped &&
         out->text_login_authoritative && out->route_consistent &&
         out->no_real_event_dispatched && out->no_real_input_dispatched;
  out->pipeline_safe = safe ? 1 : 0;

  if (out->pipeline_safe) {
    out->event_type = "credential-screen-pipeline-safety-report-ready";
    out->state = "pipeline-safe";
    out->blocked_reason = "ready";
    out->message =
        "Loginwindow credential pipeline safety verified across 15 window "
        "layers; graphical authentication remains disabled.";
  } else {
    out->event_type = "credential-screen-pipeline-safety-report-unsafe";
    out->state = "pipeline-unsafe";
    out->blocked_reason = "pipeline-safety-violated";
    out->message =
        "Loginwindow credential pipeline safety violated; use text login.";
  }
  return 0;
}

int login_window_view_model_build(const struct login_window_contract *contract,
                                  const char *language,
                                  struct login_window_view_model *out) {
  const char *lang = localization_normalize_language(language);
  if (!out) return -1;
  if (!lang) lang = "en";
  out->renderable = 0;
  out->password_enabled = 0;
  out->recovery_enabled = 0;
  out->fallback_required = 1;
  out->maintenance_notice = 0;
  (void)login_window_credential_policy_from_contract(contract,
                                                     &out->credential_policy);
  out->password_submit_enabled = out->credential_policy.password_submit_allowed;
  out->password_masked = out->credential_policy.password_mask_required;
  out->credential_wipe_required = out->credential_policy.password_wipe_required;
  out->text_login_authoritative = out->credential_policy.text_login_authoritative;
  out->state = "blocked";
  out->title = localization_select(lang, "Login grafico indisponivel",
                                   "Graphical login unavailable",
                                   "Inicio grafico no disponible");
  out->message = localization_select(lang,
                                     "O login textual permanece ativo.",
                                     "Text login remains active.",
                                     "El inicio textual permanece activo.");
  out->blocked_reason = "contract-unavailable";
  if (!contract) return 0;
  out->blocked_reason = contract->blocked_reason ? contract->blocked_reason
                                                 : "blocked";
  if (contract->ready) {
    out->renderable = 1;
    out->password_enabled = out->credential_policy.password_field_allowed;
    out->fallback_required = out->credential_policy.password_submit_allowed ? 0 : 1;
    out->state = "ready";
    out->title = "CapyOS";
    out->message = localization_select(lang,
                                       "Campo de senha reservado; use o login textual.",
                                       "Password field reserved; use text login.",
                                       "Campo de contrasena reservado; usa el inicio textual.");
    return 0;
  }
  if (!contract->has_input) {
    out->state = "input-unavailable";
    out->message = localization_select(lang,
                                       "Nenhum dispositivo de entrada disponivel.",
                                       "No input device is available.",
                                       "No hay dispositivo de entrada disponible.");
    return 0;
  }
  if (!contract->session_available || !contract->settings_available ||
      !contract->shell_callbacks_ready || !contract->auth_callbacks_ready ||
      !contract->ui_callbacks_ready) {
    out->state = "runtime-incomplete";
    out->message = localization_select(lang,
                                       "Runtime de login incompleto; usando login textual.",
                                       "Login runtime incomplete; using text login.",
                                       "Runtime de inicio incompleto; usando inicio textual.");
    return 0;
  }
  if (contract->maintenance_mode) {
    out->renderable = 1;
    out->recovery_enabled = out->credential_policy.recovery_allowed;
    out->maintenance_notice = 1;
    out->state = "maintenance";
    out->title = localization_select(lang, "Modo de recuperacao",
                                     "Recovery mode", "Modo de recuperacion");
    out->message = contract->recovery_available
                       ? localization_select(lang,
                                             "Sessao textual de recuperacao disponivel.",
                                             "Text recovery session is available.",
                                             "Sesion textual de recuperacion disponible.")
                       : localization_select(lang,
                                             "Recuperacao indisponivel; use o TTY.",
                                             "Recovery unavailable; use the TTY.",
                                             "Recuperacion no disponible; usa el TTY.");
    return 0;
  }
  out->state = "blocked";
  return 0;
}

static int login_consume_recovery_login_request(struct login_runtime_ops *ops) {
  if (!ops || !ops->consume_recovery_login_request) {
    return 0;
  }
  return ops->consume_recovery_login_request() ? 1 : 0;
}

static void login_show_maintenance_notice(struct login_runtime_ops *ops,
                                          const char *language,
                                          int maintenance_mode) {
  if (!ops || !maintenance_mode) {
    return;
  }

  ops->print(localization_select(
      language,
      "[maintenance] Sistema iniciado em modo de recuperacao.\n",
      "[maintenance] System booted in recovery mode.\n",
      "[maintenance] Sistema iniciado en modo de recuperacion.\n"));
  if (ops->maintenance_reason && ops->maintenance_reason[0]) {
    ops->print(localization_select(language, "Motivo: ", "Reason: ",
                                   "Motivo: "));
    ops->print(ops->maintenance_reason);
    ops->putc('\n');
  }
  ops->print(localization_select(
      language,
      "Use service-status, service-target show, do-sync e shutdown-reboot para diagnostico e recuperacao.\n",
      "Use service-status, service-target show, do-sync and shutdown-reboot for diagnosis and recovery.\n",
      "Usa service-status, service-target show, do-sync y shutdown-reboot para diagnostico y recuperacion.\n"));
}

static const char *login_view_text(const char *text, const char *fallback) {
  return (text && text[0]) ? text : fallback;
}

static void login_render_window_preview(struct login_runtime_ops *ops,
                                        const char *language) {
  struct login_window_contract contract;
  struct login_window_view_model model;
  if (!ops || !ops->print) return;
  if (login_window_contract_evaluate(ops, &contract) != 0) return;
  if (login_window_view_model_build(&contract, language, &model) != 0) return;

  ops->print("\n+------------------------------------------+\n");
  ops->print("| CapyOS loginwindow preview              |\n");
  ops->print("+------------------------------------------+\n");
  ops->print("title: ");
  ops->print(login_view_text(model.title, "CapyOS"));
  ops->print("\nstate: ");
  ops->print(login_view_text(model.state, "blocked"));
  ops->print("\nmessage: ");
  ops->print(login_view_text(model.message, "Text login remains active."));
  ops->print("\nreason: ");
  ops->print(login_view_text(model.blocked_reason, "blocked"));
  ops->print(model.password_enabled
                 ? "\npassword-field: contract-ready; masked; GUI submit disabled\n"
                 : "\npassword-field: disabled; use text login\n");
  ops->print(model.password_submit_enabled
                 ? "password-submit: enabled\n"
                 : "password-submit: disabled; text login authoritative\n");
  ops->print(model.credential_wipe_required
                 ? "credential-buffer: ephemeral; wipe-required\n"
                 : "credential-buffer: unavailable\n");
  ops->print(model.credential_policy.recovery_requires_text_session
                 ? "recovery-policy: text-session-only\n"
                 : "recovery-policy: gui-eligible\n");
  ops->print(model.recovery_enabled
                 ? "recovery-action: available through text recovery\n"
                 : "recovery-action: disabled\n");
  ops->print(model.fallback_required
                 ? "fallback: text login required\n"
                 : "fallback: text login remains authoritative\n");
  ops->print("+------------------------------------------+\n");
}

static void login_render_screen(struct login_runtime_ops *ops,
                                const char *language, int first_screen,
                                int maintenance_mode) {
  if (!ops) {
    return;
  }
  if (first_screen) {
    ops->show_splash(ops->settings);
  }
  ops->clear_view();
  ops->ui_banner();
  if (ops->render_window_layout) {
    ops->render_window_layout();
  } else {
    login_render_window_preview(ops, language);
  }
  if (maintenance_mode) {
    ops->print("\n");
    login_show_maintenance_notice(ops, language, maintenance_mode);
  }
}

int login_runtime_run(struct login_runtime_ops *ops) {
  int first_login_screen = 1;
  char line[128];
  struct login_window_contract login_window;
  const char *system_language = "en";

  dbg_login_puts("[lr] enter\n");
  if (!ops_ready(ops)) {
    dbg_login_puts("[lr] ops not ready\n");
    return -1;
  }
  if (ops->settings && ops->settings->language[0]) {
    const char *normalized = localization_normalize_language(ops->settings->language);
    if (normalized) {
      system_language = normalized;
    }
  }

  if (ops->prepare_shell_runtime() != 0) {
    dbg_login_puts("[lr] prepare_shell_runtime retry\n");
    ops->print(localization_text_for(system_language,
                                     LOC_TEXT_PREPARE_SHELL_FAILED));
    /* Do not abort — the runtime may be partially ready (enough for
     * login to function), or a second attempt may succeed.  Halting
     * here would make the system completely unusable. */
    (void)ops->prepare_shell_runtime();
  }
  dbg_login_puts("[lr] shell runtime ready\n");
  login_service_poll(ops);

  for (;;) {
    int maintenance_mode = 0;
    if (login_window_contract_evaluate(ops, &login_window) != 0) {
      return -1;
    }
    maintenance_mode = login_window.maintenance_mode;
    if (first_login_screen) {
      dbg_login_puts("[lr] render screen\n");
      login_render_screen(ops, system_language, 1, maintenance_mode);
      first_login_screen = 0;
    }
    ops->print("\n");

    if (!login_window.has_input) {
      ops->print(localization_text_for(system_language, LOC_TEXT_NO_INPUT_DEVICE));
    }

    ops->session_reset(ops->session_ctx);
    ops->session_set_active(NULL);
    ops->shell_context_init(ops->shell_ctx, ops->session_ctx, ops->settings);
    login_service_poll(ops);

    if (maintenance_mode) {
      if (ops->maintenance_session_start(ops->session_ctx, ops->settings) != 0) {
        ops->print(localization_select(
            system_language,
            "[erro] Falha ao iniciar a sessao de recuperacao.\n",
            "[error] Failed to start the recovery session.\n",
            "[error] No fue posible iniciar la sesion de recuperacion.\n"));
        return -1;
      }
    } else {
      dbg_login_puts("[lr] system_login begin\n");
      if (ops->system_login(ops->session_ctx, ops->settings) != 0) {
        dbg_login_puts("[lr] system_login failed\n");
        ops->print(
            localization_text_for(system_language, LOC_TEXT_AUTH_FLOW_FAILED));
        return -1;
      }
      dbg_login_puts("[lr] system_login ok\n");
    }
    dbg_login_puts("[lr] post-login service_poll begin\n");
    login_service_poll(ops);
    dbg_login_puts("[lr] post-login service_poll end\n");

    {
      const struct user_record *login_user = ops->session_user(ops->session_ctx);
      const char *language = session_language(ops->session_ctx);
      if (!login_user || !login_user->username[0] ||
          ops->init_shell_context_user(login_user) != 0) {
        dbg_login_puts("[lr] init shell ctx failed\n");
        ops->print(
            localization_text_for(language, LOC_TEXT_SESSION_ACTIVATION_FAILED));
        ops->print(localization_text_for(language, LOC_TEXT_RETURNING_TO_LOGIN));
        continue;
      }
      dbg_login_puts("[lr] init shell ctx ok\n");
    }

    for (;;) {
      const struct user_record *active_user = ops->session_user(ops->session_ctx);
      const char *cwd = ops->session_cwd(ops->session_ctx);
      char prompt[128];

      login_service_poll(ops);
      shell_build_prompt(active_user, ops->settings, cwd, prompt,
                         sizeof(prompt));
      ops->print(prompt);

      ops->readline(line, sizeof(line), 0);
      login_service_poll(ops);
      if (!line[0]) {
        continue;
      }

      if (ops->dispatch_shell_command(line)) {
        login_service_poll(ops);
        if (maintenance_mode) {
          int resume_requested = login_consume_recovery_login_request(ops);
          struct login_recovery_resume_policy resume_policy;
          if (login_recovery_resume_policy_evaluate(ops, 1, resume_requested,
                                                    &resume_policy) != 0) {
            return -1;
          }
          if (resume_policy.can_resume_normal_login) {
            ops->print(localization_select(
                system_language,
                "[recovery] Sessao de recuperacao encerrada. Voltando para o login normal.\n",
                "[recovery] Recovery session closed. Returning to the normal login.\n",
                "[recovery] Sesion de recuperacion cerrada. Volviendo al inicio de sesion normal.\n"));
            ops->session_reset(ops->session_ctx);
            ops->session_set_active(NULL);
            login_render_screen(ops, system_language, 0, 0);
            break;
          }
          if (resume_requested) {
            ops->print(localization_select(
                system_language,
                "[recovery] Retorno ao login normal bloqueado: ",
                "[recovery] Normal login return blocked: ",
                "[recovery] Retorno al inicio normal bloqueado: "));
            ops->print(resume_policy.blocked_reason);
            ops->putc('\n');
          }
        }
        if (ops->shell_context_should_logout(ops->shell_ctx)) {
          ops->session_reset(ops->session_ctx);
          ops->session_set_active(NULL);
          login_render_screen(ops, system_language, 0,
                              login_maintenance_mode_active(ops));
          break;
        }
        continue;
      }

      if (ops->is_equal(line, "help")) {
        (void)ops->run_shell_alias("help-any");
        login_service_poll(ops);
        continue;
      }
      if (ops->is_equal(line, "clear")) {
        (void)ops->run_shell_alias("mess");
        login_service_poll(ops);
        continue;
      }
      if (ops->is_equal(line, "reboot")) {
        (void)ops->run_shell_alias("shutdown-reboot");
        login_service_poll(ops);
        continue;
      }
      if (ops->is_equal(line, "halt")) {
        (void)ops->run_shell_alias("shutdown-off");
        login_service_poll(ops);
        continue;
      }
      if (ops->is_equal(line, "info")) {
        ops->cmd_info();
        login_service_poll(ops);
        continue;
      }

      ops->print(localization_text_for(session_language(ops->session_ctx),
                                       LOC_TEXT_UNKNOWN_COMMAND_PREFIX));
      ops->print(line);
      ops->print(localization_text_for(session_language(ops->session_ctx),
                                       LOC_TEXT_UNKNOWN_COMMAND_HINT));
      login_service_poll(ops);
    }
  }
}
